import { GoogleGenAI } from "@google/genai";
import { ModOption } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generatePatchScript = async (fileName: string, activeMods: ModOption[]): Promise<string> => {
  if (!apiKey) {
    return "// API Key missing. Cannot generate patch script.\n// Please check your environment configuration.";
  }

  const modList = activeMods.map(m => m.name).join(', ');
  const prompt = `
    You are a specialized code generator for a game modding tool called "Nexus Mod Manager".

    Task: Generate a hypothetical patch script or configuration snippet for a file named "${fileName}".
    Applied Mods: ${modList}.

    Requirements:
    1. Detect the likely language based on the file extension (e.g., .apk -> Java/Smali snippet, .json -> JSON, .lua -> Lua, .exe -> C++/Assembly pseudocode).
    2. Provide code that *represents* these changes conceptually.
    3. Include comments explaining what lines are being "injected".
    4. Keep it concise (under 20 lines of code).
    5. This is for educational/simulation purposes.

    Output Format: Just the code block, no markdown backticks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || '// No code generated';
  } catch (error) {
    console.error("Gemini API Error:", error);
    return `// Error generating patch: ${(error as Error).message}`;
  }
};

export const analyzeFile = async (fileName: string): Promise<string> => {
    if (!apiKey) return "API Key missing.";

    const prompt = `Analyze the filename "${fileName}" and provide a short, 1-sentence technical description of what this file likely contains and its structure (e.g. "Android Package File containing compiled Dalvik bytecode").`;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        return response.text || 'Analysis failed.';
    } catch (error) {
        return "Analysis unavailable.";
    }
}

import React from 'react';
