};

import React, { useEffect, useRef } from 'react';
import { PatchLog } from '../types';

interface TerminalProps {
  logs: PatchLog[];
  isProcessing: boolean;
}

export const Terminal: React.FC<TerminalProps> = ({ logs, isProcessing }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  return (
    <div className="bg-nexus-900 rounded-lg border border-nexus-700 font-mono text-xs md:text-sm h-64 flex flex-col shadow-inner overflow-hidden relative">
      <div className="bg-nexus-800 px-4 py-2 flex items-center justify-between border-b border-nexus-700">
        <span className="text-gray-400 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-red-500"></div>
            <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
            <div className="w-2 h-2 rounded-full bg-green-500"></div>
            Nexus_Core_Terminal
        </span>
        <span className="text-nexus-accent text-xs opacity-50">v2.4.1-stable</span>
      </div>

      <div className="flex-1 p-4 overflow-y-auto space-y-1 relative">
        {logs.map((log, index) => (
          <div key={index} className={`flex gap-3 ${
            log.type === 'error' ? 'text-nexus-danger' : 
            log.type === 'success' ? 'text-nexus-accent' : 
            log.type === 'code' ? 'text-blue-300 pl-4 border-l-2 border-blue-500/30' : 
            log.type === 'warning' ? 'text-nexus-warning' : 'text-gray-400'
          }`}>
            <span className="opacity-50 select-none">[{log.timestamp}]</span>
            <span className="whitespace-pre-wrap">{log.message}</span>
          </div>
        ))}

        {isProcessing && (
          <div className="text-nexus-accent animate-pulse">
            > Processing request... <span className="inline-block w-2 h-4 bg-nexus-accent align-middle ml-1 animate-pulse"></span>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* CRT Scanline Effect Overlay */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-10 bg-[length:100%_2px,3px_100%] opacity-20"></div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { FileData, ModOption, PatchLog } from '../types';
import { Upload, HardDrive, Cpu, Check, Play, Lock } from 'lucide-react';
import { Terminal } from './Terminal';
import { generatePatchScript, analyzeFile } from '../services/geminiService';
import { MOCK_FILES } from '../constants';

interface DashboardProps {
  mods: ModOption[];
  onToggleMod: (id: string) => void;
  isPremium: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ mods, onToggleMod, isPremium }) => {
  const [selectedFile, setSelectedFile] = useState<FileData | null>(null);
  const [logs, setLogs] = useState<PatchLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [generatedCode, setGeneratedCode] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'console' | 'preview'>('console');

  const addLog = (message: string, type: PatchLog['type'] = 'info') => {
    const timestamp = new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
    setLogs(prev => [...prev, { timestamp, message, type }]);
  };

  useEffect(() => {
    addLog('System initialized. Ready for input.', 'info');
  }, []);

  const handleFileSelect = async (file: FileData) => {
    setSelectedFile(file);
    addLog(`Target selected: ${file.name} (${file.size})`, 'info');
    setIsProcessing(true);

    // Simulate analysis
    const analysis = await analyzeFile(file.name);
    addLog(`Analysis complete: ${analysis}`, 'success');
    setIsProcessing(false);
  };

  const handlePatch = async () => {
    if (!selectedFile) {
      addLog('Error: No target file selected.', 'error');
      return;
    }

    const activeMods = mods.filter(m => m.active);
    if (activeMods.length === 0) {
      addLog('Warning: No modification modules selected.', 'warning');
      return;
    }

    setIsProcessing(true);
    addLog('Initiating patch sequence...', 'info');
    addLog(`Modules active: ${activeMods.length}`, 'info');

    // Simulate connection delay
    setTimeout(async () => {
        try {
            const script = await generatePatchScript(selectedFile.name, activeMods);
            setGeneratedCode(script);
            addLog('Payload generated successfully.', 'success');
            addLog(script.substring(0, 100) + '...', 'code');
            addLog('Patch applied to virtual buffer.', 'success');
            setActiveTab('preview');
        } catch (e) {
            addLog('Patch generation failed.', 'error');
        } finally {
            setIsProcessing(false);
        }
    }, 1500);
  };

  return (
    <div className="flex flex-col h-full overflow-hidden p-6 space-y-6">

      {/* Header Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-blue-500/10 rounded-lg text-blue-400">
            <HardDrive size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">Storage</p>
            <p className="text-lg font-bold">2.4 TB / 5.0 TB</p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-nexus-accentDim rounded-lg text-nexus-accent">
            <Cpu size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">CPU Load</p>
            <p className="text-lg font-bold">12% Idle</p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
            <div className={`p-3 rounded-lg ${selectedFile ? 'bg-purple-500/10 text-purple-400' : 'bg-gray-700/20 text-gray-600'}`}>
                <FileCode size={24} />
            </div>
            <div>
                <p className="text-xs text-gray-400 uppercase">Active Target</p>
                <p className="text-lg font-bold truncate max-w-[150px]">{selectedFile ? selectedFile.name : 'None'}</p>
            </div>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-6 min-h-0">

        {/* Left Col: File Manager & Mods */}
        <div className="lg:col-span-2 flex flex-col space-y-6 overflow-y-auto pr-2">

            {/* File Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center">
                    <span className="w-1 h-6 bg-nexus-accent mr-3 rounded-full"></span>
                    Target Selection
                </h3>
                <div className="grid grid-cols-1 gap-3">
                    {MOCK_FILES.map(file => (
                         <div 
                            key={file.id}
                            onClick={() => handleFileSelect(file as unknown as FileData)}
                            className={`p-4 rounded-lg border cursor-pointer transition-all flex justify-between items-center ${
                                selectedFile?.id === file.id 
                                ? 'bg-nexus-700 border-nexus-accent shadow-[0_0_10px_rgba(0,255,157,0.1)]' 
                                : 'bg-nexus-900 border-nexus-700 hover:border-gray-500'
                            }`}
                         >
                            <div className="flex items-center space-x-3">
                                <div className="p-2 bg-nexus-800 rounded">
                                    <FileCode size={20} className="text-gray-300"/>
                                </div>
                                <div>
                                    <p className="font-semibold text-sm">{file.name}</p>
                                    <p className="text-xs text-gray-500">{file.size} • {file.type.split('/')[1]}</p>
                                </div>
                            </div>
                            {selectedFile?.id === file.id && <div className="text-nexus-accent"><Check size={20}/></div>}
                         </div>
                    ))}

                    <div className="border-2 border-dashed border-nexus-700 rounded-lg p-6 flex flex-col items-center justify-center text-gray-500 hover:border-nexus-accent hover:text-nexus-accent transition-colors cursor-pointer group">
                        <Upload size={24} className="mb-2 group-hover:scale-110 transition-transform"/>
                        <p className="text-sm font-medium">Drop external APK / IPA / EXE</p>
                    </div>
                </div>
            </div>

            {/* Mod Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center justify-between">
                    <div className="flex items-center">
                        <span className="w-1 h-6 bg-purple-500 mr-3 rounded-full"></span>
                        Injection Modules
                    </div>
                    {isPremium && <span className="text-xs bg-purple-500/20 text-purple-300 px-2 py-1 rounded border border-purple-500/30">PREMIUM UNLOCKED</span>}
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {mods.map(mod => (
                        <div 
                            key={mod.id}
                            onClick={() => {
                                if (mod.isPremium && !isPremium) return;
                                onToggleMod(mod.id);
                            }}
                            className={`relative p-4 rounded-lg border transition-all ${
                                mod.active 
                                ? 'bg-nexus-700 border-nexus-accent' 
                                : mod.isPremium && !isPremium 
                                    ? 'bg-nexus-900/50 border-nexus-700 opacity-60 cursor-not-allowed' 
                                    : 'bg-nexus-900 border-nexus-700 cursor-pointer hover:border-gray-500'
                            }`}
                        >
                            <div className="flex justify-between items-start mb-2">
                                <span className={`font-bold text-sm ${mod.active ? 'text-white' : 'text-gray-300'}`}>{mod.name}</span>
                                {mod.active ? (
                                    <div className="w-4 h-4 rounded-full bg-nexus-accent shadow-[0_0_8px_#00ff9d]"></div>
                                ) : (
                                    <div className="w-4 h-4 rounded-full border border-gray-600"></div>
                                )}
                            </div>
                            <p className="text-xs text-gray-500 leading-relaxed">{mod.description}</p>

                            {mod.isPremium && !isPremium && (
                                <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[1px] rounded-lg">
                                    <div className="flex items-center space-x-2 text-nexus-warning bg-black/80 px-3 py-1 rounded-full border border-nexus-warning/30">
                                        <Lock size={12} />
                                        <span className="text-xs font-bold">LOCKED</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        {/* Right Col: Console & Action */}
        <div className="flex flex-col space-y-6">

            {/* Action Button */}
            <button
                onClick={handlePatch}
                disabled={isProcessing || !selectedFile}
                className={`w-full py-6 rounded-xl font-bold text-lg tracking-widest uppercase transition-all flex items-center justify-center space-x-3 shadow-lg ${
                    isProcessing || !selectedFile
                    ? 'bg-gray-800 text-gray-500 cursor-not-allowed'
                    : 'bg-nexus-accent text-nexus-900 hover:bg-white hover:shadow-[0_0_25px_rgba(0,255,157,0.6)] active:scale-95'
                }`}
            >
                {isProcessing ? (
                    <span className="animate-pulse">Compiling...</span>
                ) : (
                    <>
                        <Play size={24} fill="currentColor" />
                        <span>Execute Patch</span>
                    </>
                )}
            </button>

            {/* Output Panel */}
            <div className="flex-1 bg-nexus-800 rounded-xl border border-nexus-700 flex flex-col overflow-hidden">
                <div className="flex border-b border-nexus-700">
                    <button 
                        onClick={() => setActiveTab('console')}
                        className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider ${activeTab === 'console' ? 'bg-nexus-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        System Log
                    </button>
                    <button 
                         onClick={() => setActiveTab('preview')}
                        className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider ${activeTab === 'preview' ? 'bg-nexus-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        Code Preview
                    </button>
                </div>

                <div className="flex-1 overflow-hidden relative">
                    {activeTab === 'console' ? (
                        <div className="h-full">
                            <Terminal logs={logs} isProcessing={isProcessing} />
                        </div>
                    ) : (
                         <div className="h-full p-4 overflow-auto font-mono text-xs text-blue-300 bg-nexus-900">
                            {generatedCode ? (
                                <pre className="whitespace-pre-wrap">{generatedCode}</pre>
                            ) : (
                                <div className="h-full flex items-center justify-center text-gray-600 italic">
                                    No patch data generated yet.
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { INITIAL_MODS } from './constants';
import { AppView, ModOption } from './types';
import { ShoppingCart, Wrench } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [isPremium, setIsPremium] = useState(false);
  const [mods, setMods] = useState<ModOption[]>(INITIAL_MODS);

  const toggleMod = (id: string) => {
    setMods(prev => prev.map(m => m.id === id ? { ...m, active: !m.active } : m));
  };

  const togglePremium = () => {
    setIsPremium(!isPremium);
  };

  const renderContent = () => {
    switch (currentView) {
      case AppView.DASHBOARD:
        return (
          <Dashboard 
            mods={mods} 
            onToggleMod={toggleMod} 
            isPremium={isPremium}
          />
        );
      case AppView.STORE:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 space-y-4">
            <div className="p-6 bg-nexus-800 rounded-full">
                <ShoppingCart size={48} className="text-nexus-accent" />
            </div>
            <h2 className="text-2xl font-bold text-white">Mod Store Offline</h2>
            <p>Connect to Nexus Network to browse community mods.</p>
          </div>
        );
      case AppView.SETTINGS:
      case AppView.EDITOR:
        return (
          <div className="flex flex-col items-center justify-center h-full text-gray-400 space-y-4">
             <div className="p-6 bg-nexus-800 rounded-full">
                <Wrench size={48} className="text-purple-400" />
            </div>
            <h2 className="text-2xl font-bold text-white">Module Under Construction</h2>
            <p>This feature will be available in the v3.0 update.</p>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-nexus-900 text-gray-200 overflow-hidden font-sans selection:bg-nexus-accent selection:text-nexus-900">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView}
        isPremium={isPremium}
        onTogglePremium={togglePremium}
      />

      <main className="flex-1 h-full bg-[#050508] relative">
        {/* Background Grid Pattern */}
        <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-[#050508] pointer-events-none"></div>

        <div className="relative h-full z-10">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

