    return "00000000: API KEY MISSING -> ABORT PROCESS\n// Please check environment configuration.";
  }

  const modList = activeMods.map(m => m.name).join(', ');
  const prompt = `
    You are a low-level binary analysis AI for a modding tool.
    Target File: "${fileName}"
    Active Injections: ${modList}

    Task: Generate a realistic-looking "Hex Dump Diff" or "Assembly Injection Log" that simulates patching this file.

    Requirements:
    1. If it's an APK/IPA, show Smali or ARM64 Assembly offsets.
    2. If it's a Save File (JSON/Binary), show Hex byte replacements.
    3. Format it like a technical patch log.
    4. Include memory addresses (e.g., 0x004F3A).
    5. Keep it under 20 lines.

    Example Output Style:
    0x0045A1: 1A 4F -> 00 00 (NOP) // Bypass Signature Check
    0x0045A2: MOV R0, #999999 // Inject Currency Value
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || '// No patch data generated';
  } catch (error) {
    console.error("Gemini API Error:", error);
    return `// Error generating patch: ${(error as Error).message}`;
  }
};

export const analyzeFile = async (fileName: string): Promise<string> => {
    if (!apiKey) return "API Key missing.";

    const prompt = `Analyze the filename "${fileName}" and provide a short, 1-sentence technical description of its binary structure (e.g. "ELF 64-bit LSB executable, x86-64").`;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        return response.text || 'Analysis failed.';
    } catch (error) {
        return "Analysis unavailable.";
    }
}

import React, { useState, useEffect, useRef } from 'react';
import { FileData, ModOption, PatchLog } from '../types';
import { Upload, HardDrive, Cpu, Check, Play, Lock, FileCode, X, Download, Binary, Code } from 'lucide-react';
import { Terminal } from './Terminal';
import { generatePatchScript, analyzeFile } from '../services/geminiService';
import { MOCK_FILES } from '../constants';

interface DashboardProps {
  mods: ModOption[];
  onToggleMod: (id: string) => void;
  isPremium: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ mods, onToggleMod, isPremium }) => {
  const [files, setFiles] = useState<FileData[]>(MOCK_FILES.map(f => ({...f, status: f.status as any})));
  const [selectedFile, setSelectedFile] = useState<FileData | null>(null);
  const [uploadedFileObj, setUploadedFileObj] = useState<File | null>(null);
  const [logs, setLogs] = useState<PatchLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processStep, setProcessStep] = useState(0); // 0: Idle, 1: Decompile, 2: Analyze, 3: Patch, 4: Recompile, 5: Sign
  const [generatedCode, setGeneratedCode] = useState<string | null>(null);
  const [hexDump, setHexDump] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'console' | 'preview' | 'hex'>('console');
  const [isDragging, setIsDragging] = useState(false);
  const [patchComplete, setPatchComplete] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addLog = (message: string, type: PatchLog['type'] = 'info') => {
    const timestamp = new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
    setLogs(prev => [...prev, { timestamp, message, type }]);
  };

  useEffect(() => {
    addLog('System initialized. Ready for input.', 'info');
  }, []);

  const readHex = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
        const buffer = e.target?.result as ArrayBuffer;
        const bytes = new Uint8Array(buffer.slice(0, 512)); // Read first 512 bytes
        let hex = '';
        for (let i = 0; i < bytes.length; i++) {
            const byte = bytes[i].toString(16).padStart(2, '0').toUpperCase();
            hex += byte + ' ';
            if ((i + 1) % 16 === 0) hex += '\n';
        }
        setHexDump(hex);
        addLog(`Binary read successful. Loaded ${bytes.length} bytes into Hex View.`, 'success');
    };
    reader.readAsArrayBuffer(file);
  };

  const handleFileSelect = async (file: FileData, fileObj?: File) => {
    setSelectedFile(file);
    setPatchComplete(false);
    setProcessStep(0);
    setGeneratedCode(null);

    addLog(`Target selected: ${file.name} (${file.size})`, 'info');

    if (fileObj) {
        setUploadedFileObj(fileObj);
        readHex(fileObj);
    } else {
        // Mock hex for mock files
        setHexDump("4E 45 58 55 53 5F 4D 4F 43 4B 5F 44 41 54 41 00\n00 00 01 0B 4F 12 C4 D3 ... (Mock Data)");
        setUploadedFileObj(null);
    }

    setIsProcessing(true);
    const analysis = await analyzeFile(file.name);
    addLog(`Analysis complete: ${analysis}`, 'success');
    setIsProcessing(false);
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleFileUpload = (uploadedFile: File) => {
    const newFile: FileData = {
        id: Math.random().toString(36).substr(2, 9),
        name: uploadedFile.name,
        size: formatFileSize(uploadedFile.size),
        type: uploadedFile.type || 'application/octet-stream',
        uploadedAt: new Date(),
        status: 'clean'
    };

    setFiles(prev => [...prev, newFile]);
    handleFileSelect(newFile, uploadedFile);
    addLog(`File loaded into buffer: ${uploadedFile.name}`, 'success');
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        handleFileUpload(e.dataTransfer.files[0]);
    }
  };

  const onFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        handleFileUpload(e.target.files[0]);
    }
  };

  const downloadPatchedFile = () => {
    if (!selectedFile) return;

    const fileName = selectedFile.name.replace(/(\.[\w\d_-]+)$/i, '_patched$1');
    const content = uploadedFileObj || new Blob(["Simulated patched content"], { type: 'application/octet-stream' });

    // Create download link
    const url = URL.createObjectURL(content);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    addLog(`Exported: ${fileName}`, 'success');
  };

  const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

  const handlePatch = async () => {
    if (!selectedFile) {
      addLog('Error: No target file selected.', 'error');
      return;
    }

    const activeMods = mods.filter(m => m.active);
    if (activeMods.length === 0) {
      addLog('Warning: No modification modules selected.', 'warning');
      return;
    }

    setIsProcessing(true);
    setPatchComplete(false);
    setActiveTab('console');

    try {
        // Step 1: Decompile
        setProcessStep(1);
        addLog('Initiating patch sequence...', 'info');
        await wait(1000);
        addLog('Decompiling resources...', 'info');

        // Step 2: Analyze
        setProcessStep(2);
        await wait(1500);
        const script = await generatePatchScript(selectedFile.name, activeMods);
        setGeneratedCode(script);
        addLog('Vulnerability analysis complete.', 'success');

        // Step 3: Inject
        setProcessStep(3);
        await wait(1000);
        addLog(`Injecting ${activeMods.length} payload modules...`, 'warning');
        activeMods.forEach(m => addLog(`> Applying: ${m.name}`, 'code'));

        // Step 4: Recompile
        setProcessStep(4);
        await wait(2000);
        addLog('Recompiling binary...', 'info');

        // Step 5: Sign
        setProcessStep(5);
        await wait(1000);
        addLog('Signing package with test certificate...', 'info');

        addLog('Patch applied successfully. Ready for export.', 'success');
        setPatchComplete(true);
        setActiveTab('preview');

    } catch (e) {
        addLog('Critical Failure in patch sequence.', 'error');
    } finally {
        setIsProcessing(false);
        setProcessStep(0);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden p-6 space-y-6">

      {/* Header Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-blue-500/10 rounded-lg text-blue-400">
            <HardDrive size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">Storage</p>
            <p className="text-lg font-bold">2.4 TB / 5.0 TB</p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-nexus-accentDim rounded-lg text-nexus-accent">
            <Cpu size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">Process</p>
            <p className="text-lg font-bold">{isProcessing ? 'Active' : 'Idle'}</p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
            <div className={`p-3 rounded-lg ${selectedFile ? 'bg-purple-500/10 text-purple-400' : 'bg-gray-700/20 text-gray-600'}`}>
                <FileCode size={24} />
            </div>
            <div>
                <p className="text-xs text-gray-400 uppercase">Target</p>
                <p className="text-lg font-bold truncate max-w-[150px]">{selectedFile ? selectedFile.name : 'None'}</p>
            </div>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-6 min-h-0">

        {/* Left Col: File Manager & Mods */}
        <div className="lg:col-span-2 flex flex-col space-y-6 overflow-y-auto pr-2">

            {/* File Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center">
                    <span className="w-1 h-6 bg-nexus-accent mr-3 rounded-full"></span>
                    Target Selection
                </h3>
                <div className="grid grid-cols-1 gap-3">
                    {files.map(file => (
                         <div 
                            key={file.id}
                            onClick={() => handleFileSelect(file)}
                            className={`p-4 rounded-lg border cursor-pointer transition-all flex justify-between items-center ${
                                selectedFile?.id === file.id 
                                ? 'bg-nexus-700 border-nexus-accent shadow-[0_0_10px_rgba(0,255,157,0.1)]' 
                                : 'bg-nexus-900 border-nexus-700 hover:border-gray-500'
                            }`}
                         >
                            <div className="flex items-center space-x-3">
                                <div className="p-2 bg-nexus-800 rounded">
                                    <FileCode size={20} className="text-gray-300"/>
                                </div>
                                <div>
                                    <p className="font-semibold text-sm">{file.name}</p>
                                    <p className="text-xs text-gray-500">{file.size} • {file.type.split('/')[1] || 'unknown'}</p>
                                </div>
                            </div>
                            {selectedFile?.id === file.id && <div className="text-nexus-accent"><Check size={20}/></div>}
                         </div>
                    ))}

                    <div 
                        onDragOver={onDragOver}
                        onDragLeave={onDragLeave}
                        onDrop={onDrop}
                        onClick={() => fileInputRef.current?.click()}
                        className={`border-2 border-dashed rounded-lg p-6 flex flex-col items-center justify-center transition-all cursor-pointer group ${
                            isDragging 
                            ? 'border-nexus-accent bg-nexus-accent/10 text-nexus-accent' 
                            : 'border-nexus-700 text-gray-500 hover:border-nexus-accent hover:text-nexus-accent'
                        }`}
                    >
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={onFileInputChange} 
                            className="hidden" 
                            // accept=".apk,.ipa,.exe,.json,.lua" // Removed restriction to allow any file
                        />
                        <Upload size={24} className={`mb-2 transition-transform ${isDragging ? 'scale-110' : 'group-hover:scale-110'}`}/>
                        <p className="text-sm font-medium">
                            {isDragging ? 'Drop to upload' : 'Drop external APK / IPA / EXE'}
                        </p>
                    </div>
                </div>
            </div>

            {/* Mod Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center justify-between">
                    <div className="flex items-center">
                        <span className="w-1 h-6 bg-purple-500 mr-3 rounded-full"></span>
                        Injection Modules
                    </div>
                    {isPremium && <span className="text-xs bg-purple-500/20 text-purple-300 px-2 py-1 rounded border border-purple-500/30">PREMIUM UNLOCKED</span>}
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {mods.map(mod => (
                        <div 
                            key={mod.id}
                            onClick={() => {
                                if (mod.isPremium && !isPremium) return;
                                onToggleMod(mod.id);
                            }}
                            className={`relative p-4 rounded-lg border transition-all ${
                                mod.active 
                                ? 'bg-nexus-700 border-nexus-accent' 
                                : mod.isPremium && !isPremium 
                                    ? 'bg-nexus-900/50 border-nexus-700 opacity-60 cursor-not-allowed' 
                                    : 'bg-nexus-900 border-nexus-700 cursor-pointer hover:border-gray-500'
                            }`}
                        >
                            <div className="flex justify-between items-start mb-2">
                                <span className={`font-bold text-sm ${mod.active ? 'text-white' : 'text-gray-300'}`}>{mod.name}</span>
                                {mod.active ? (
                                    <div className="w-4 h-4 rounded-full bg-nexus-accent shadow-[0_0_8px_#00ff9d]"></div>
                                ) : (
                                    <div className="w-4 h-4 rounded-full border border-gray-600"></div>
                                )}
                            </div>
                            <p className="text-xs text-gray-500 leading-relaxed">{mod.description}</p>

                            {mod.isPremium && !isPremium && (
                                <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[1px] rounded-lg">
                                    <div className="flex items-center space-x-2 text-nexus-warning bg-black/80 px-3 py-1 rounded-full border border-nexus-warning/30">
                                        <Lock size={12} />
                                        <span className="text-xs font-bold">LOCKED</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        {/* Right Col: Console & Action */}
        <div className="flex flex-col space-y-6">

            {/* Action Button */}
            {!patchComplete ? (
                <button
                    onClick={handlePatch}
                    disabled={isProcessing || !selectedFile}
                    className={`w-full py-6 rounded-xl font-bold text-lg tracking-widest uppercase transition-all flex items-center justify-center space-x-3 shadow-lg overflow-hidden relative ${
