              <item.icon size={18} className={`transition-colors ${currentView === item.id ? 'text-nexus-accent' : 'text-gray-500 group-hover:text-white'}`} />
              <span className="font-medium text-sm">{item.label}</span>
            </button>
          ))}
        </nav>
      </div>

      <div className="p-4">
        <div className="rounded-xl p-4 bg-nexus-700/30 border border-nexus-700">
            <div className="flex items-center space-x-2 mb-2">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                <span className="text-xs font-bold uppercase tracking-widest text-gray-500">
                    System Online
                </span>
            </div>
            <p className="text-xs text-gray-400">
                Connected to Nexus Cloud. All modules loaded.
            </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { FileData, ModOption, PatchLog } from '../types';
import { Upload, HardDrive, Cpu, Check, Play, FileCode, X, Download, Binary, Code, Coins, RefreshCw } from 'lucide-react';
import { Terminal } from './Terminal';
import { generatePatchScript, analyzeFile, identifyCurrencies } from '../services/geminiService';
import { MOCK_FILES } from '../constants';

interface DashboardProps {
  mods: ModOption[];
  onToggleMod: (id: string) => void;
  updateMod: (id: string, updates: Partial<ModOption>) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ mods, onToggleMod, updateMod }) => {
  const [files, setFiles] = useState<FileData[]>(MOCK_FILES.map(f => ({...f, status: f.status as any})));
  const [selectedFile, setSelectedFile] = useState<FileData | null>(null);
  const [uploadedFileObj, setUploadedFileObj] = useState<File | null>(null);
  const [fileContent, setFileContent] = useState<string | ArrayBuffer | null>(null);
  const [logs, setLogs] = useState<PatchLog[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processStep, setProcessStep] = useState(0); 
  const [generatedCode, setGeneratedCode] = useState<string | null>(null);
  const [hexDump, setHexDump] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'console' | 'preview' | 'hex'>('console');
  const [isDragging, setIsDragging] = useState(false);
  const [patchComplete, setPatchComplete] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addLog = (message: string, type: PatchLog['type'] = 'info') => {
    const timestamp = new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
    setLogs(prev => [...prev, { timestamp, message, type }]);
  };

  useEffect(() => {
    addLog('Nexus Core v3.0 initialized.', 'info');
    addLog('Premium restrictions disabled. All modules unlocked.', 'success');
  }, []);

  const readHex = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
        const buffer = e.target?.result as ArrayBuffer;
        setFileContent(buffer);

        // Generate Hex View
        const bytes = new Uint8Array(buffer.slice(0, 512)); 
        let hex = '';
        for (let i = 0; i < bytes.length; i++) {
            const byte = bytes[i].toString(16).padStart(2, '0').toUpperCase();
            hex += byte + ' ';
            if ((i + 1) % 16 === 0) hex += '\n';
        }
        setHexDump(hex);
        addLog(`Binary loaded: ${file.name} (${bytes.length} bytes preview)`, 'success');
    };
    reader.readAsArrayBuffer(file);
  };

  const readText = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          const text = e.target?.result as string;
          setFileContent(text);
          setGeneratedCode(text); // Populate preview with actual content
          setHexDump(''); 
          addLog(`Text file loaded: ${file.name}`, 'success');

          // Auto-detect keys in JSON
          if (file.name.endsWith('.json')) {
              try {
                  const json = JSON.parse(text);
                  const keys = [];
                  const traverse = (obj: any) => {
                      for (const k in obj) {
                          if (typeof obj[k] === 'number') {
                              if (['money', 'gold', 'cash', 'coins', 'gems', 'credits', 'balance'].some(t => k.toLowerCase().includes(t))) {
                                  keys.push(k);
                              }
                          }
                          if (typeof obj[k] === 'object' && obj[k] !== null) traverse(obj[k]);
                      }
                  }
                  traverse(json);
                  if (keys.length > 0) {
                      addLog(`Detected currency keys in JSON: ${keys.join(', ')}`, 'success');
                      updateMod('unlimited_currency', { 
                          name: `Unlimited ${keys.slice(0, 2).join(' & ')}`,
                          description: `Set ${keys.join(', ')} to 999,999,999`
                      });
                  }
              } catch(e) {}
          }
      };
      reader.readAsText(file);
  }

  const handleFileSelect = async (file: FileData, fileObj?: File) => {
    setSelectedFile(file);
    setPatchComplete(false);
    setProcessStep(0);
    setGeneratedCode(null);
    setHexDump('');
    setFileContent(null);

    // Reset Currency Mod to default state while analyzing
    updateMod('unlimited_currency', { name: 'Unlimited Currency', description: 'Detecting economy system...' });

    addLog(`Target selected: ${file.name}`, 'info');

    if (fileObj) {
        setUploadedFileObj(fileObj);
        if (file.name.endsWith('.json') || file.name.endsWith('.txt') || file.name.endsWith('.xml')) {
            readText(fileObj);
            setActiveTab('preview');
        } else {
            readHex(fileObj);
            setActiveTab('hex');

            // AI Detection for Binaries
            addLog('Analyzing package for economy assets...', 'info');
            const currencies = await identifyCurrencies(file.name);
            if (currencies.length > 0) {
                 const currencyStr = currencies.join(' & ');
                 addLog(`Economy identified: ${currencyStr}`, 'success');
                 updateMod('unlimited_currency', { 
                    name: `Unlimited ${currencyStr}`,
                    description: `Injects max value for ${currencies.join(', ')}`
                 });
            }
        }
    } else {
        // Mock data logic
        if (file.name.endsWith('.json')) {
             const mockJson = JSON.stringify({
                 "player": { "name": "Hero", "level": 15, "exp": 4500 },
                 "inventory": { "gold": 120, "gems": 5 },
                 "settings": { "volume": 80 }
             }, null, 2);
             setGeneratedCode(mockJson);
             setFileContent(mockJson);
             setActiveTab('preview');
             updateMod('unlimited_currency', { name: 'Unlimited Gold & Gems', description: 'Set gold and gems to 999,999,999' });
        } else {
            setHexDump("4E 45 58 55 53 5F 4D 4F 43 4B 5F 44 41 54 41 00\n00 00 01 0B 4F 12 C4 D3 ... (Mock Data)");
            setActiveTab('hex');
            // Mock AI detection
             updateMod('unlimited_currency', { name: 'Unlimited Credits', description: 'Injects max value for Credits' });
        }
        setUploadedFileObj(null);
    }

    setIsProcessing(true);
    const analysis = await analyzeFile(file.name);
    addLog(`Engine Analysis: ${analysis}`, 'success');
    setIsProcessing(false);
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleFileUpload = (uploadedFile: File) => {
    const newFile: FileData = {
        id: Math.random().toString(36).substr(2, 9),
        name: uploadedFile.name,
        size: formatFileSize(uploadedFile.size),
        type: uploadedFile.type || 'application/octet-stream',
        uploadedAt: new Date(),
        status: 'clean'
    };

    setFiles(prev => [...prev, newFile]);
    handleFileSelect(newFile, uploadedFile);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        handleFileUpload(e.dataTransfer.files[0]);
    }
  };

  const onFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        handleFileUpload(e.target.files[0]);
    }
  };

  const downloadPatchedFile = () => {
    if (!selectedFile) return;

    let content: BlobPart;
    let fileName = selectedFile.name;

    if (generatedCode && (selectedFile.name.endsWith('.json') || selectedFile.name.endsWith('.txt'))) {
        content = generatedCode;
        fileName = selectedFile.name.replace(/(\.[\w\d_-]+)$/i, '_patched$1');
    } else if (uploadedFileObj) {
        content = uploadedFileObj;
        fileName = selectedFile.name.replace(/(\.[\w\d_-]+)$/i, '_simulated$1');
    } else {
        content = new Blob(["Simulation only"], { type: 'text/plain' });
    }

    const blob = new Blob([content], { type: 'application/octet-stream' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    addLog(`Downloaded: ${fileName}`, 'success');
  };

  const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

  const applyRealJsonMods = (jsonString: string, activeMods: ModOption[]) => {
      try {
          const data = JSON.parse(jsonString);
          let modified = false;

          const traverse = (obj: any) => {
              for (const k in obj) {
                  if (typeof obj[k] === 'object' && obj[k] !== null) {
                      traverse(obj[k]);
                  } else if (typeof obj[k] === 'number') {
                      if (activeMods.find(m => m.id === 'unlimited_currency')) {
                          if (['money', 'gold', 'cash', 'coins', 'gems', 'credits', 'balance', 'exp'].some(term => k.toLowerCase().includes(term))) {
                              obj[k] = 999999999;
                              addLog(`[REAL] Patched key '${k}': ${obj[k]}`, 'code');
                              modified = true;
                          }
                      }
                      if (activeMods.find(m => m.id === 'unlock_all')) {
                          if (['locked', 'islocked'].includes(k.toLowerCase())) {
                              obj[k] = 0; 
                              modified = true;
                          }
                      }
                  } else if (typeof obj[k] === 'boolean') {
                       if (activeMods.find(m => m.id === 'unlock_all')) {
                          if (['locked', 'islocked'].includes(k.toLowerCase())) {
                              obj[k] = false;
                              addLog(`[REAL] Unlocked '${k}'`, 'code');
                              modified = true;
                          }
                          if (['unlocked', 'isunlocked'].includes(k.toLowerCase())) {
                              obj[k] = true;
                              addLog(`[REAL] Unlocked '${k}'`, 'code');
                              modified = true;
                          }
                      }
                  }
              }
          };

          traverse(data);

          if (!modified) {
              addLog('No matching keys found for selected mods in JSON.', 'warning');
          } else {
              addLog('JSON data structure successfully modified.', 'success');
          }

          return JSON.stringify(data, null, 2);
      } catch (e) {
          addLog('Error parsing JSON for real patching.', 'error');
          return jsonString;
      }
  };

  const handlePatch = async () => {
    if (!selectedFile) {
      addLog('Error: No target file selected.', 'error');
      return;
    }

    const activeMods = mods.filter(m => m.active);
    if (activeMods.length === 0) {
      addLog('Warning: No modification modules selected.', 'warning');
      return;
    }

    setIsProcessing(true);
    setPatchComplete(false);
    setActiveTab('console');

    // REAL PATCHING PATH for JSON/Text
    if (selectedFile.name.endsWith('.json') || selectedFile.name.endsWith('.txt')) {
        setProcessStep(1);
        addLog('Detected text-based configuration file.', 'info');
        await wait(500);

        setProcessStep(2);
        addLog('Parsing data structure...', 'info');
        await wait(500);

        setProcessStep(3);
        const currentContent = typeof fileContent === 'string' ? fileContent : '';
        const newContent = applyRealJsonMods(currentContent, activeMods);
        setGeneratedCode(newContent);

        setProcessStep(5);
        addLog('Real-time modifications applied to buffer.', 'success');
        setPatchComplete(true);
        setIsProcessing(false);
        setActiveTab('preview');
        return;
    }

    // SIMULATION PATH for Binaries
    try {
        setProcessStep(1);
        addLog('Binary file detected. Starting simulation sequence...', 'info');
        await wait(1000);
        addLog('Decompiling (Simulation)...', 'info');

        setProcessStep(2);
        await wait(1000);
        const script = await generatePatchScript(selectedFile.name, activeMods);
        setGeneratedCode(script);

        setProcessStep(3);
        await wait(800);
        activeMods.forEach(m => addLog(`> Simulating injection: ${m.name}`, 'code'));

        setProcessStep(4);
        await wait(1000);
        addLog('Recompiling binary (Simulation)...', 'info');

        setProcessStep(5);
        await wait(500);
        addLog('Simulation complete. File ready for export.', 'success');
        setPatchComplete(true);
        setActiveTab('preview');

    } catch (e) {
        addLog('Critical Failure in patch sequence.', 'error');
    } finally {
        setIsProcessing(false);
        setProcessStep(0);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden p-6 space-y-6">

      {/* Header Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-blue-500/10 rounded-lg text-blue-400">
            <HardDrive size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">File Buffer</p>
            <p className="text-lg font-bold">
                {selectedFile ? 'Loaded' : 'Empty'}
            </p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
          <div className="p-3 bg-nexus-accentDim rounded-lg text-nexus-accent">
            <Cpu size={24} />
          </div>
          <div>
            <p className="text-xs text-gray-400 uppercase">Engine Status</p>
            <p className="text-lg font-bold">{isProcessing ? 'Processing' : 'Standby'}</p>
          </div>
        </div>
        <div className="bg-nexus-800 p-4 rounded-xl border border-nexus-700 flex items-center space-x-4">
            <div className={`p-3 rounded-lg ${selectedFile ? 'bg-purple-500/10 text-purple-400' : 'bg-gray-700/20 text-gray-600'}`}>
                <FileCode size={24} />
            </div>
            <div>
                <p className="text-xs text-gray-400 uppercase">Active Target</p>
                <p className="text-lg font-bold truncate max-w-[150px]">{selectedFile ? selectedFile.name : 'None'}</p>
            </div>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-6 min-h-0">

        {/* Left Col: File Manager & Mods */}
        <div className="lg:col-span-2 flex flex-col space-y-6 overflow-y-auto pr-2">

            {/* File Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center justify-between">
                    <div className="flex items-center">
                        <span className="w-1 h-6 bg-nexus-accent mr-3 rounded-full"></span>
                        Target Selection
                    </div>
                    {selectedFile && selectedFile.name.endsWith('.json') && (
                         <span className="text-xs bg-green-500/20 text-green-400 px-2 py-1 rounded border border-green-500/30 font-bold animate-pulse">
                            REAL EDIT MODE
                         </span>
                    )}
                     {selectedFile && !selectedFile.name.endsWith('.json') && !selectedFile.name.endsWith('.txt') && (
                         <span className="text-xs bg-blue-500/20 text-blue-400 px-2 py-1 rounded border border-blue-500/30 font-bold">
                            SIMULATION MODE
                         </span>
                    )}
                </h3>
                <div className="grid grid-cols-1 gap-3">
                    {files.map(file => (
                         <div 
                            key={file.id}
                            onClick={() => handleFileSelect(file)}
                            className={`p-4 rounded-lg border cursor-pointer transition-all flex justify-between items-center ${
                                selectedFile?.id === file.id 
                                ? 'bg-nexus-700 border-nexus-accent shadow-[0_0_10px_rgba(0,255,157,0.1)]' 
                                : 'bg-nexus-900 border-nexus-700 hover:border-gray-500'
                            }`}
                         >
                            <div className="flex items-center space-x-3">
                                <div className="p-2 bg-nexus-800 rounded">
                                    <FileCode size={20} className="text-gray-300"/>
                                </div>
                                <div>
                                    <p className="font-semibold text-sm">{file.name}</p>
                                    <p className="text-xs text-gray-500">{file.size} • {file.type.split('/')[1] || 'unknown'}</p>
                                </div>
                            </div>
                            {selectedFile?.id === file.id && <div className="text-nexus-accent"><Check size={20}/></div>}
                         </div>
                    ))}

                    <div 
                        onDragOver={onDragOver}
                        onDragLeave={onDragLeave}
                        onDrop={onDrop}
                        onClick={() => fileInputRef.current?.click()}
                        className={`border-2 border-dashed rounded-lg p-6 flex flex-col items-center justify-center transition-all cursor-pointer group ${
                            isDragging 
                            ? 'border-nexus-accent bg-nexus-accent/10 text-nexus-accent' 
                            : 'border-nexus-700 text-gray-500 hover:border-nexus-accent hover:text-nexus-accent'
                        }`}
                    >
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={onFileInputChange} 
                            className="hidden" 
                        />
                        <Upload size={24} className={`mb-2 transition-transform ${isDragging ? 'scale-110' : 'group-hover:scale-110'}`}/>
                        <p className="text-sm font-medium">
                            {isDragging ? 'Drop to upload' : 'Drop .json (Save File) or .apk (Sim)'}
                        </p>
                        <p className="text-xs text-gray-600 mt-2">
                             System will attempt to identify assets in dropped files.
                        </p>
                    </div>
                </div>
            </div>

            {/* Mod Selection */}
            <div className="bg-nexus-800 rounded-xl border border-nexus-700 p-6">
                <h3 className="text-lg font-bold mb-4 flex items-center justify-between">
                    <div className="flex items-center">
                        <span className="w-1 h-6 bg-purple-500 mr-3 rounded-full"></span>
                        Injection Modules
                    </div>
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {mods.map(mod => (
                        <div 
                            key={mod.id}
                            onClick={() => onToggleMod(mod.id)}
                            className={`relative p-4 rounded-lg border transition-all cursor-pointer hover:border-gray-500 ${
                                mod.active 
                                ? 'bg-nexus-700 border-nexus-accent' 
                                : 'bg-nexus-900 border-nexus-700'
                            }`}
                        >
                            <div className="flex justify-between items-start mb-2">
                                <span className={`font-bold text-sm ${mod.active ? 'text-white' : 'text-gray-300'}`}>{mod.name}</span>
                                {mod.active ? (
                                    <div className="w-4 h-4 rounded-full bg-nexus-accent shadow-[0_0_8px_#00ff9d]"></div>
                                ) : (
                                    <div className="w-4 h-4 rounded-full border border-gray-600"></div>
                                )}
                            </div>
                            <p className="text-xs text-gray-500 leading-relaxed">{mod.description}</p>
                        </div>
                    ))}
                </div>
            </div>
        </div>

        {/* Right Col: Console & Action */}
        <div className="flex flex-col space-y-6">

            {/* Action Button */}
            {!patchComplete ? (
                <button
                    onClick={handlePatch}
                    disabled={isProcessing || !selectedFile}
                    className={`w-full py-6 rounded-xl font-bold text-lg tracking-widest uppercase transition-all flex items-center justify-center space-x-3 shadow-lg overflow-hidden relative ${
                        isProcessing || !selectedFile
                        ? 'bg-gray-800 text-gray-500 cursor-not-allowed'
                        : 'bg-nexus-accent text-nexus-900 hover:bg-white hover:shadow-[0_0_25px_rgba(0,255,157,0.6)] active:scale-95'
                    }`}
                >
                    {isProcessing && (
                        <div 
                            className="absolute left-0 top-0 bottom-0 bg-black/10 transition-all duration-300" 
                            style={{width: `${(processStep / 5) * 100}%`}}
                        ></div>
                    )}
                    <div className="relative z-10 flex items-center space-x-2">
                        {isProcessing ? (
                            <>
                                <span className="animate-spin text-xl">◌</span>
                                <span>
                                    {selectedFile?.name.endsWith('.json') ? 'Applying Edits...' : 'Simulating Patch...'}
                                </span>
                            </>
                        ) : (
                            <>
                                <Play size={24} fill="currentColor" />
                                <span>Execute Patch</span>
                            </>
                        )}
                    </div>
                </button>
            ) : (
                <button
                    onClick={downloadPatchedFile}
                    className="w-full py-6 rounded-xl font-bold text-lg tracking-widest uppercase transition-all flex items-center justify-center space-x-3 shadow-lg bg-blue-500 text-white hover:bg-blue-400 hover:shadow-[0_0_25px_rgba(59,130,246,0.6)] active:scale-95"
                >
                    <Download size={24} />
                    <span>Download {selectedFile?.name.endsWith('.json') ? 'Edited JSON' : 'Simulated File'}</span>
                </button>
            )}

            {/* Output Panel */}
            <div className="flex-1 bg-nexus-800 rounded-xl border border-nexus-700 flex flex-col overflow-hidden">
                <div className="flex border-b border-nexus-700">
                    <button 
                        onClick={() => setActiveTab('console')}
                        className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 ${activeTab === 'console' ? 'bg-nexus-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        <Binary size={14} /> Log
                    </button>
                    <button 
                         onClick={() => setActiveTab('preview')}
                        className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 ${activeTab === 'preview' ? 'bg-nexus-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        <Code size={14} /> {selectedFile?.name.endsWith('.json') ? 'Editor' : 'Preview'}
                    </button>
                    {(!selectedFile || (!selectedFile.name.endsWith('.json') && !selectedFile.name.endsWith('.txt'))) && (
                        <button 
                            onClick={() => setActiveTab('hex')}
                            className={`flex-1 py-3 text-xs font-bold uppercase tracking-wider flex items-center justify-center gap-2 ${activeTab === 'hex' ? 'bg-nexus-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}
                        >
                            <Binary size={14} /> Hex
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-hidden relative">
                    {activeTab === 'console' && (
                        <div className="h-full">
                            <Terminal logs={logs} isProcessing={isProcessing} />
                        </div>
                    )}

                    {activeTab === 'preview' && (
                         <div className="h-full flex flex-col bg-nexus-900">
                            {generatedCode ? (
                                <textarea 
                                    className="flex-1 w-full h-full p-4 bg-nexus-900 text-blue-300 font-mono text-xs outline-none border-none resize-none"
                                    value={generatedCode}
                                    onChange={(e) => setGeneratedCode(e.target.value)}
                                    spellCheck={false}
                                />
                            ) : (
                                <div className="h-full flex items-center justify-center text-gray-600 italic">
                                    No file content loaded.
                                </div>
                            )}
                            {generatedCode && selectedFile?.name.endsWith('.json') && (
                                <div className="p-2 bg-nexus-800 text-xs text-center text-gray-500 border-t border-nexus-700">
                                    Editable Mode: Changes will be saved on download.
                                </div>
                            )}
                        </div>
                    )}

                    {activeTab === 'hex' && (
                        <div className="h-full p-4 overflow-auto font-mono text-xs text-nexus-accent bg-black">
                            <pre className="whitespace-pre-wrap tracking-wider leading-relaxed opacity-80">
                                {hexDump || "No binary file loaded."}
                            </pre>
                        </div>
                    )}
                </div>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
